  1→"use client";
  2→
  3→import { memo, useCallback, useRef, useMemo, useState } from "react";
  4→import { Search, X, ChevronDown } from "lucide-react";
  5→import { Input } from "@/components/ui/input";
  6→import { Button } from "@/components/ui/button";
  7→import { ScrollArea } from "@/components/ui/scroll-area";
  8→import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
  9→import {
 10→  DropdownMenu,
 11→  DropdownMenuContent,
 12→  DropdownMenuItem,
 13→  DropdownMenuTrigger,
 14→  DropdownMenuLabel,
 15→  DropdownMenuSeparator,
 16→} from "@/components/ui/dropdown-menu";
 17→import { useFlowStore } from "@/store/useFlowStore";
 18→import { useLocale } from "@/lib/i18n/useLocale";
 19→import { BulkEditNodeIcon } from "./BulkEditNodeIcon";
 20→import { BulkEditEdgeIcon } from "./BulkEditEdgeIcon";
 21→import type { FlowNode, FlowEdge } from "@/store/types";
 22→import type { NodeShape, EdgeType } from "@/types/flow";
 23→import type { TranslationKey } from "@/lib/i18n/locales";
 24→
 25→type ViewMode = "category" | "flow";
 26→type BulkEditItem =
 27→  | { kind: "node"; node: FlowNode }
 28→  | { kind: "edge"; edge: FlowEdge }
 29→  | { kind: "section"; label: string };
 30→
 31→interface BulkEditTableProps {
 32→  onFocusNode: (nodeId: string) => void;
 33→  onFocusEdge: (edgeId: string) => void;
 34→  highlightId: string | null;
 35→  selectedIds: string[];
 36→}
 37→
 38→const SHAPE_FILTER_OPTIONS: { value: NodeShape; key: TranslationKey }[] = [
 39→  { value: "rectangle", key: "rectangle" },
 40→  { value: "roundedRect", key: "roundedRect" },
 41→  { value: "diamond", key: "diamond" },
 42→  { value: "circle", key: "circle" },
 43→  { value: "stadium", key: "stadium" },
 44→  { value: "parallelogram", key: "parallelogram" },
 45→  { value: "cylinder", key: "cylinder" },
 46→  { value: "hexagon", key: "hexagon" },
 47→  { value: "trapezoid", key: "trapezoid" },
 48→  { value: "document", key: "document" },
 49→  { value: "predefinedProcess", key: "predefinedProcess" },
 50→  { value: "manualInput", key: "manualInput" },
 51→  { value: "internalStorage", key: "internalStorage" },
 52→  { value: "display", key: "display" },
 53→  { value: "text", key: "freeText" },
 54→];
 55→
 56→const EDGE_FILTER_OPTIONS: { value: EdgeType; key: TranslationKey }[] = [
 57→  { value: "bezier", key: "bezier" },
 58→  { value: "straight", key: "straight" },
 59→  { value: "step", key: "step" },
 60→];
 61→
 62→const DEFAULT_EDGE_TYPE: EdgeType = "bezier";
 63→
 64→// ---- Row components ----
 65→
 66→const NodeRow = memo(function NodeRow({
 67→  node,
 68→  isHighlighted,
 69→  onFocus,
 70→  onLabelChange,
 71→  index,
 72→  inputRefsRef,
 73→}: {
 74→  node: FlowNode;
 75→  isHighlighted: boolean;
 76→  onFocus: (id: string) => void;
 77→  onLabelChange: (id: string, label: string) => void;
 78→  index: number;
 79→  inputRefsRef: React.RefObject<(HTMLInputElement | null)[]>;
 80→}) {
 81→  const isComponentInstance = !!node.data.componentDefinitionId;
 82→  const displayLabel = isComponentInstance
 83→    ? (node.data.componentInstanceName ?? node.data.label)
 84→    : node.data.label;
 85→
 86→  const setRef = useCallback(
 87→    (el: HTMLInputElement | null) => {
 88→      if (inputRefsRef.current) inputRefsRef.current[index] = el;
 89→    },
 90→    [index, inputRefsRef]
 91→  );
 92→
 93→  return (
 94→    <div
 95→      className={`flex items-center gap-2 px-2 py-1 rounded cursor-pointer transition-colors ${
 96→        isHighlighted ? "bg-primary/10" : "hover:bg-muted/50"
 97→      }`}
 98→      onClick={() => onFocus(node.id)}
 99→    >
100→      <BulkEditNodeIcon
101→        shape={node.data.shape}
102→        fillColor={node.data.fillColor}
103→        fillOpacity={node.data.fillOpacity}
104→        fillLightness={node.data.fillLightness}
105→        borderColor={node.data.borderColor}
106→        borderOpacity={node.data.borderOpacity}
107→        borderLightness={node.data.borderLightness}
108→        borderWidth={node.data.borderWidth}
109→        borderStyle={node.data.borderStyle}
110→      />
111→      <Input
112→        ref={setRef}
113→        className="h-7 text-sm flex-1"
114→        value={displayLabel}
115→        onChange={(e) => onLabelChange(node.id, e.target.value)}
116→        onFocus={() => onFocus(node.id)}
117→        onClick={(e) => e.stopPropagation()}
118→      />
119→    </div>
120→  );
121→});
122→
123→const EdgeRow = memo(function EdgeRow({
124→  edge,
125→  isHighlighted,
126→  onFocus,
127→  onLabelChange,
128→  index,
129→  inputRefsRef,
130→}: {
131→  edge: FlowEdge;
132→  isHighlighted: boolean;
133→  onFocus: (id: string) => void;
134→  onLabelChange: (id: string, label: string) => void;
135→  index: number;
136→  inputRefsRef: React.RefObject<(HTMLInputElement | null)[]>;
137→}) {
138→  const setRef = useCallback(
139→    (el: HTMLInputElement | null) => {
140→      if (inputRefsRef.current) inputRefsRef.current[index] = el;
141→    },
142→    [index, inputRefsRef]
143→  );
144→
145→  return (
146→    <div
147→      className={`flex items-center gap-2 px-2 py-1 rounded cursor-pointer transition-colors ${
148→        isHighlighted ? "bg-primary/10" : "hover:bg-muted/50"
149→      }`}
150→      onClick={() => onFocus(edge.id)}
151→    >
152→      <BulkEditEdgeIcon
153→        strokeColor={edge.data?.strokeColor}
154→        strokeOpacity={edge.data?.strokeOpacity}
155→        strokeLightness={edge.data?.strokeLightness}
156→        strokeWidth={edge.data?.strokeWidth}
157→        strokeStyle={edge.data?.strokeStyle}
158→        markerEnd={edge.data?.markerEnd}
159→        markerStart={edge.data?.markerStart}
160→      />
161→      <span className="text-[10px] text-muted-foreground whitespace-nowrap shrink-0">
162→        {edge.source}→{edge.target}
163→      </span>
164→      <Input
165→        ref={setRef}
166→        className="h-7 text-sm flex-1"
167→        value={edge.data?.label ?? ""}
168→        onChange={(e) => onLabelChange(edge.id, e.target.value)}
169→        onFocus={() => onFocus(edge.id)}
170→        onClick={(e) => e.stopPropagation()}
171→      />
172→    </div>
173→  );
174→});
175→
176→// ---- Flow order computation ----
177→
178→/** Topological sort via BFS from root nodes (no incoming edges).
179→ *  Interleaves nodes and their outgoing edges in traversal order. */
180→function buildFlowOrder(nodes: FlowNode[], edges: FlowEdge[]): BulkEditItem[] {
181→  const nodeMap = new Map(nodes.map((n) => [n.id, n]));
182→  const incomingCount = new Map<string, number>();
183→  const outgoingEdges = new Map<string, FlowEdge[]>();
184→
185→  for (const n of nodes) {
186→    incomingCount.set(n.id, 0);
187→    outgoingEdges.set(n.id, []);
188→  }
189→  for (const e of edges) {
190→    incomingCount.set(e.target, (incomingCount.get(e.target) ?? 0) + 1);
191→    outgoingEdges.get(e.source)?.push(e);
192→  }
193→
194→  // Start from nodes with no incoming edges
195→  const queue: string[] = [];
196→  for (const n of nodes) {
197→    if ((incomingCount.get(n.id) ?? 0) === 0) {
198→      queue.push(n.id);
199→    }
200→  }
201→
202→  const visited = new Set<string>();
203→  const visitedEdges = new Set<string>();
204→  const items: BulkEditItem[] = [];
205→
206→  while (queue.length > 0) {
207→    const id = queue.shift()!;
208→    if (visited.has(id)) continue;
209→    visited.add(id);
210→
211→    const node = nodeMap.get(id);
212→    if (node) items.push({ kind: "node", node });
213→
214→    for (const edge of outgoingEdges.get(id) ?? []) {
215→      if (visitedEdges.has(edge.id)) continue;
216→      visitedEdges.add(edge.id);
217→      items.push({ kind: "edge", edge });
218→
219→      if (!visited.has(edge.target)) {
220→        // Decrement and enqueue if all incoming visited
221→        const remaining = (incomingCount.get(edge.target) ?? 1) - 1;
222→        incomingCount.set(edge.target, remaining);
223→        if (remaining <= 0) {
224→          queue.push(edge.target);
225→        }
226→      }
227→    }
228→  }
229→
230→  // Add any remaining unvisited nodes (disconnected or in cycles)
231→  for (const n of nodes) {
232→    if (!visited.has(n.id)) {
233→      items.push({ kind: "node", node: n });
234→      for (const edge of outgoingEdges.get(n.id) ?? []) {
235→        if (!visitedEdges.has(edge.id)) {
236→          visitedEdges.add(edge.id);
237→          items.push({ kind: "edge", edge });
238→        }
239→      }
240→    }
241→  }
242→
243→  // Add any remaining edges not yet included
244→  for (const e of edges) {
245→    if (!visitedEdges.has(e.id)) {
246→      items.push({ kind: "edge", edge: e });
247→    }
248→  }
249→
250→  return items;
251→}
252→
253→// ---- Main component ----
254→
255→export const BulkEditTable = memo(function BulkEditTable({
256→  onFocusNode,
257→  onFocusEdge,
258→  highlightId,
259→  selectedIds,
260→}: BulkEditTableProps) {
261→  const nodes = useFlowStore((s) => s.nodes);
262→  const edges = useFlowStore((s) => s.edges);
263→  const updateNodeLabel = useFlowStore((s) => s.updateNodeLabel);
264→  const updateEdgeLabel = useFlowStore((s) => s.updateEdgeLabel);
265→  const updateComponentInstanceName = useFlowStore(
266→    (s) => s.updateComponentInstanceName
267→  );
268→  const { t } = useLocale();
269→
270→  const [viewMode, setViewMode] = useState<ViewMode>("category");
271→  const [searchText, setSearchText] = useState("");
272→  // Unified filter: "" = all, "shape:rectangle" = node shape, "edge:bezier" = edge type
273→  const [filter, setFilter] = useState("");
274→
275→  const shapeFilter = filter.startsWith("shape:") ? filter.slice(6) as NodeShape : "";
276→  const edgeTypeFilter = filter.startsWith("edge:") ? filter.slice(5) as EdgeType : "";
277→
278→  // Canvas multi-selection override
279→  const selectedIdsSet = useMemo(() => new Set(selectedIds), [selectedIds]);
280→  const hasSelection = selectedIdsSet.size > 0;
281→
282→  const editableNodes = useMemo(
283→    () => nodes.filter((n) => !n.data.componentParentId && !n.data.isLocked),
284→    [nodes]
285→  );
286→  const editableEdges = useMemo(
287→    () => edges.filter((e) => !e.data?.isBridgeEdge),
288→    [edges]
289→  );
290→
291→  // Apply text search filter
292→  const searchLower = searchText.toLowerCase();
293→
294→  const filteredNodes = useMemo(() => {
295→    // Canvas multi-selection overrides all filters
296→    if (hasSelection) {
297→      return editableNodes.filter((n) => selectedIdsSet.has(n.id));
298→    }
299→    // Edge type filter active → hide all nodes
300→    if (edgeTypeFilter) return [];
301→    let result = editableNodes;
302→    if (searchText) {
303→      result = result.filter((n) => {
304→        const label = n.data.componentInstanceName ?? n.data.label;
305→        return label.toLowerCase().includes(searchLower);
306→      });
307→    }
308→    if (shapeFilter) {
309→      result = result.filter((n) => n.data.shape === shapeFilter);
310→    }
311→    return result;
312→  }, [editableNodes, searchLower, searchText, shapeFilter, edgeTypeFilter, hasSelection, selectedIdsSet]);
313→
314→  const filteredEdges = useMemo(() => {
315→    // Canvas multi-selection → show edges connected to selected nodes
316→    if (hasSelection) {
317→      return editableEdges.filter(
318→        (e) => selectedIdsSet.has(e.source) || selectedIdsSet.has(e.target)
319→      );
320→    }
321→    // Shape filter active → only edges connected to matching nodes
322→    if (shapeFilter) {
323→      const matchingNodeIds = new Set(filteredNodes.map((n) => n.id));
324→      let result = editableEdges.filter(
325→        (e) => matchingNodeIds.has(e.source) || matchingNodeIds.has(e.target)
326→      );
327→      if (searchText) {
328→        result = result.filter((e) =>
329→          (e.data?.label ?? "").toLowerCase().includes(searchLower)
330→        );
331→      }
332→      return result;
333→    }
334→    let result = editableEdges;
335→    if (edgeTypeFilter) {
336→      result = result.filter(
337→        (e) => (e.data?.edgeType ?? DEFAULT_EDGE_TYPE) === edgeTypeFilter
338→      );
339→    }
340→    if (searchText) {
341→      result = result.filter((e) =>
342→        (e.data?.label ?? "").toLowerCase().includes(searchLower)
343→      );
344→    }
345→    return result;
346→  }, [editableEdges, shapeFilter, filteredNodes, edgeTypeFilter, searchLower, searchText, hasSelection, selectedIdsSet]);
347→
348→  // Build items list based on view mode
349→  const items = useMemo((): BulkEditItem[] => {
350→    if (viewMode === "flow") {
351→      return buildFlowOrder(filteredNodes, filteredEdges);
352→    }
353→    // Category mode: nodes section header, nodes, edges section header, edges
354→    const result: BulkEditItem[] = [];
355→    result.push({ kind: "section", label: t("nodes") });
356→    for (const node of filteredNodes) {
357→      result.push({ kind: "node", node });
358→    }
359→    result.push({ kind: "section", label: t("bulkEditEdges") });
360→    for (const edge of filteredEdges) {
361→      result.push({ kind: "edge", edge });
362→    }
363→    return result;
364→  }, [viewMode, filteredNodes, filteredEdges, t]);
365→
366→  // Refs for keyboard navigation
367→  const inputRefsRef = useRef<(HTMLInputElement | null)[]>([]);
368→
369→  // Use useRef to avoid stale closure in handleNodeLabelChange
370→  const nodesRef = useRef(nodes);
371→  nodesRef.current = nodes;
372→
373→  const handleKeyDown = useCallback(
374→    (e: React.KeyboardEvent, index: number) => {
375→      if (e.key === "Enter" || (e.key === "Tab" && !e.shiftKey)) {
376→        e.preventDefault();
377→        const next = index + 1;
378→        if (inputRefsRef.current[next]) {
379→          inputRefsRef.current[next]?.focus();
380→        }
381→      } else if (e.key === "Tab" && e.shiftKey) {
382→        e.preventDefault();
383→        const prev = index - 1;
384→        if (prev >= 0) {
385→          inputRefsRef.current[prev]?.focus();
386→        }
387→      }
388→    },
389→    []
390→  );
391→
392→  const handleNodeLabelChange = useCallback(
393→    (id: string, label: string) => {
394→      const node = nodesRef.current.find((n) => n.id === id);
395→      if (node?.data.componentDefinitionId) {
396→        updateComponentInstanceName(id, label);
397→      } else {
398→        updateNodeLabel(id, label);
399→      }
400→    },
401→    [updateNodeLabel, updateComponentInstanceName]
402→  );
403→
404→  const handleEdgeLabelChange = useCallback(
405→    (id: string, label: string) => {
406→      updateEdgeLabel(id, label);
407→    },
408→    [updateEdgeLabel]
409→  );
410→
411→  // Compute input index (skip section headers)
412→  let inputIndex = 0;
413→
414→  return (
415→    <div className="h-full flex flex-col bg-background">
416→      {/* Toolbar: search + shape filter + view mode */}
417→      <div className="px-3 pt-3 pb-2 space-y-2 border-b border-border shrink-0">
418→        {/* Search with clear button */}
419→        <div className="relative">
420→          <Search
421→            size={14}
422→            className="absolute left-2 top-1/2 -translate-y-1/2 text-muted-foreground"
423→          />
424→          <Input
425→            className="h-7 text-sm pl-7 pr-7"
426→            placeholder={t("bulkEditSearch")}
427→            value={searchText}
428→            onChange={(e) => setSearchText(e.target.value)}
429→          />
430→          {searchText && (
431→            <button
432→              className="absolute right-1.5 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
433→              onClick={() => setSearchText("")}
434→            >
435→              <X size={14} />
436→            </button>
437→          )}
438→        </div>
439→
440→        <div className="flex items-center gap-2">
441→          {/* Unified filter dropdown */}
442→          <DropdownMenu>
443→            <DropdownMenuTrigger asChild>
444→              <Button
445→                variant="outline"
446→                size="sm"
447→                className="h-7 text-xs gap-1 flex-1 min-w-0 justify-between"
448→              >
449→                <span className="flex items-center gap-1.5 truncate">
450→                  {shapeFilter ? (
451→                    <>
452→                      <BulkEditNodeIcon shape={shapeFilter} />
453→                      {t(SHAPE_FILTER_OPTIONS.find((o) => o.value === shapeFilter)?.key ?? "rectangle")}
454→                    </>
455→                  ) : edgeTypeFilter ? (
456→                    <>
457→                      <BulkEditEdgeIcon />
458→                      {t(EDGE_FILTER_OPTIONS.find((o) => o.value === edgeTypeFilter)?.key ?? "bezier")}
459→                    </>
460→                  ) : (
461→                    t("all")
462→                  )}
463→                </span>
464→                <ChevronDown size={12} className="shrink-0 text-muted-foreground" />
465→              </Button>
466→            </DropdownMenuTrigger>
467→            <DropdownMenuContent align="start" className="max-h-72 overflow-y-auto">
468→              <DropdownMenuItem onClick={() => setFilter("")}>
469→                {t("all")}
470→              </DropdownMenuItem>
471→              <DropdownMenuSeparator />
472→              <DropdownMenuLabel className="text-[10px]">{t("nodes")}</DropdownMenuLabel>
473→              {SHAPE_FILTER_OPTIONS.map(({ value, key }) => (
474→                <DropdownMenuItem
475→                  key={value}
476→                  onClick={() => setFilter(`shape:${value}`)}
477→                  className="gap-2"
478→                >
479→                  <BulkEditNodeIcon shape={value} />
480→                  <span>{t(key)}</span>
481→                </DropdownMenuItem>
482→              ))}
483→              <DropdownMenuSeparator />
484→              <DropdownMenuLabel className="text-[10px]">{t("bulkEditEdges")}</DropdownMenuLabel>
485→              {EDGE_FILTER_OPTIONS.map(({ value, key }) => (
486→                <DropdownMenuItem
487→                  key={value}
488→                  onClick={() => setFilter(`edge:${value}`)}
489→                  className="gap-2"
490→                >
491→                  <BulkEditEdgeIcon />
492→                  <span>{t(key)}</span>
493→                </DropdownMenuItem>
494→              ))}
495→            </DropdownMenuContent>
496→          </DropdownMenu>
497→
498→          {/* View mode toggle */}
499→          <ToggleGroup
500→            type="single"
501→            value={viewMode}
502→            onValueChange={(val) => {
503→              if (val) setViewMode(val as ViewMode);
504→            }}
505→            className="h-7 shrink-0"
506→          >
507→            <ToggleGroupItem value="category" className="h-7 px-2 text-[10px]">
508→              {t("bulkEditViewCategory")}
509→            </ToggleGroupItem>
510→            <ToggleGroupItem value="flow" className="h-7 px-2 text-[10px]">
511→              {t("bulkEditViewFlow")}
512→            </ToggleGroupItem>
513→          </ToggleGroup>
514→        </div>
515→      </div>
516→
517→      {/* Items list */}
518→      <ScrollArea className="flex-1">
519→        <div className="p-3 space-y-1">
520→          {items.map((item) => {
521→            if (item.kind === "section") {
522→              return (
523→                <div
524→                  key={`section-${item.label}`}
525→                  className="text-xs font-semibold uppercase text-muted-foreground px-2 py-1 mt-1 first:mt-0"
526→                >
527→                  {item.label}
528→                </div>
529→              );
530→            }
531→
532→            if (item.kind === "node") {
533→              const idx = inputIndex++;
534→              return (
535→                <div key={item.node.id} onKeyDown={(e) => handleKeyDown(e, idx)}>
536→                  <NodeRow
537→                    node={item.node}
538→                    isHighlighted={highlightId === item.node.id}
539→                    onFocus={onFocusNode}
540→                    onLabelChange={handleNodeLabelChange}
541→                    index={idx}
542→                    inputRefsRef={inputRefsRef}
543→                  />
544→                </div>
545→              );
546→            }
547→
548→            // edge
549→            const idx = inputIndex++;
550→            return (
551→              <div key={item.edge.id} onKeyDown={(e) => handleKeyDown(e, idx)}>
552→                <EdgeRow
553→                  edge={item.edge}
554→                  isHighlighted={highlightId === item.edge.id}
555→                  onFocus={onFocusEdge}
556→                  onLabelChange={handleEdgeLabelChange}
557→                  index={idx}
558→                  inputRefsRef={inputRefsRef}
559→                />
560→              </div>
561→            );
562→          })}
563→
564→          {items.filter((i) => i.kind !== "section").length === 0 && (
565→            <div className="text-xs text-muted-foreground px-2 py-2">—</div>
566→          )}
567→        </div>
568→      </ScrollArea>
569→    </div>
570→  );
571→});
