176→// ---- Flow order computation ----
177→
178→/** Topological sort via BFS from root nodes (no incoming edges).
179→ *  Interleaves nodes and their outgoing edges in traversal order. */
180→function buildFlowOrder(nodes: FlowNode[], edges: FlowEdge[]): BulkEditItem[] {
181→  const nodeMap = new Map(nodes.map((n) => [n.id, n]));
182→  const incomingCount = new Map<string, number>();
183→  const outgoingEdges = new Map<string, FlowEdge[]>();
184→
185→  for (const n of nodes) {
186→    incomingCount.set(n.id, 0);
187→    outgoingEdges.set(n.id, []);
188→  }
189→  for (const e of edges) {
190→    incomingCount.set(e.target, (incomingCount.get(e.target) ?? 0) + 1);
191→    outgoingEdges.get(e.source)?.push(e);
192→  }
193→
194→  // Start from nodes with no incoming edges
195→  const queue: string[] = [];
196→  for (const n of nodes) {
197→    if ((incomingCount.get(n.id) ?? 0) === 0) {
198→      queue.push(n.id);
199→    }
200→  }
201→
202→  const visited = new Set<string>();
203→  const visitedEdges = new Set<string>();
204→  const items: BulkEditItem[] = [];
205→
206→  while (queue.length > 0) {
207→    const id = queue.shift()!;
208→    if (visited.has(id)) continue;
209→    visited.add(id);
210→
211→    const node = nodeMap.get(id);
212→    if (node) items.push({ kind: "node", node });
213→
214→    for (const edge of outgoingEdges.get(id) ?? []) {
215→      if (visitedEdges.has(edge.id)) continue;
216→      visitedEdges.add(edge.id);
217→      items.push({ kind: "edge", edge });
218→
219→      if (!visited.has(edge.target)) {
220→        // Decrement and enqueue if all incoming visited
221→        const remaining = (incomingCount.get(edge.target) ?? 1) - 1;
222→        incomingCount.set(edge.target, remaining);
223→        if (remaining <= 0) {
224→          queue.push(edge.target);
225→        }
226→      }
227→    }
228→  }
229→
230→  // Add any remaining unvisited nodes (disconnected or in cycles)
231→  for (const n of nodes) {
232→    if (!visited.has(n.id)) {
233→      items.push({ kind: "node", node: n });
234→      for (const edge of outgoingEdges.get(n.id) ?? []) {
235→        if (!visitedEdges.has(edge.id)) {
236→          visitedEdges.add(edge.id);
237→          items.push({ kind: "edge", edge });
238→        }
239→      }
240→    }
241→  }
242→
243→  // Add any remaining edges not yet included
244→  for (const e of edges) {
245→    if (!visitedEdges.has(e.id)) {
246→      items.push({ kind: "edge", edge: e });
247→    }
248→  }
249→
250→  return items;

348→  // Build items list based on view mode
349→  const items = useMemo((): BulkEditItem[] => {
350→    if (viewMode === "flow") {
351→      return buildFlowOrder(filteredNodes, filteredEdges);
352→    }
353→    // Category mode: nodes section header, nodes, edges section header, edges
354→    const result: BulkEditItem[] = [];
355→    result.push({ kind: "section", label: t("nodes") });
356→    for (const node of filteredNodes) {
357→      result.push({ kind: "node", node });
358→    }
359→    result.push({ kind: "section", label: t("bulkEditEdges") });
360→    for (const edge of filteredEdges) {
361→      result.push({ kind: "edge", edge });
362→    }
363→    return result;
364→  }, [viewMode, filteredNodes, filteredEdges, t]);
365→
366→  // Refs for keyboard navigation
367→  const inputRefsRef = useRef<(HTMLInputElement | null)[]>([]);
368→
369→  // Use useRef to avoid stale closure in handleNodeLabelChange
370→  const nodesRef = useRef(nodes);
371→  nodesRef.current = nodes;
