        e.preventDefault();
        const next = index + 1;
        if (inputRefsRef.current[next]) {
          inputRefsRef.current[next]?.focus();
        }
      } else if (e.key === "Tab" && e.shiftKey) {
        e.preventDefault();
        const prev = index - 1;
        if (prev >= 0) {
          inputRefsRef.current[prev]?.focus();
        }
      }
    },
    []
  );

