    const pa = posMap.get(a.source) ?? { x: 0, y: 0 };
    const pb = posMap.get(b.source) ?? { x: 0, y: 0 };
    if (direction === "LR") {
      return pa.x - pb.x || pa.y - pb.y;
    }
    return pa.y - pb.y || pa.x - pb.x;
  });
}

